
-- ===================== Data (INSERT/UPDATE/DELETE) =====================

-- Only NULL out DisplayName when it exactly matches the related entity's Name,
-- meaning it was auto-generated by CodeGen. Preserve any custom display names.
UPDATE __mj."EntityRelationship" AS er
SET
	"DisplayName" = NULL
FROM
	__mj."Entity" e1,
	__mj."Entity" e2
WHERE
	er."EntityID" = e1."ID"
	AND er."RelatedEntityID" = e2."ID"
	AND e1."SchemaName" = '__mj'
	AND e2."SchemaName" = '__mj'
	AND er."DisplayName" = e2."Name";
